+    /// Encode Expert FFN using HYBRID Q2_K + Sparse Outlier mode (Zell v2.0)
+    /// Uses Q2_K base weights (RAM-resident) + FP16 sparse corrections
+    /// Formula: y = Q2K_matmul(x, W_q2k) + sparse_correction(x, outliers)
+    pub fn encodeExpertFFN_Q2K_Hybrid(
+        self: *Self,
+        cmd_buf: objc.MTLCommandBuffer,
+        input_buf: objc.MTLBuffer,
+        gate_q2k_buf: objc.MTLBuffer, // Q2_K gate weights (RAM-resident)
+        up_q2k_buf: objc.MTLBuffer, // Q2_K up weights (RAM-resident)
+        down_q2k_buf: objc.MTLBuffer, // Q2_K down weights (RAM-resident)
+        output_buf: objc.MTLBuffer,
+        weight: f32,
+        layer_idx: u32,
+        expert_idx: u32,
+        n_embd: u32,
+        n_ff: u32,
+    ) !void {
+        const buf_idx = layer_idx * 8 + expert_idx;
+
+        // Get CSR buffers for this expert
+        const gate_row_ptr = self.hybrid_csr_gate_row_ptr[buf_idx];
+        const gate_col_idx = self.hybrid_csr_gate_col_idx[buf_idx];
+        const gate_values = self.hybrid_csr_gate_values[buf_idx];
+        const up_row_ptr = self.hybrid_csr_up_row_ptr[buf_idx];
+        const up_col_idx = self.hybrid_csr_up_col_idx[buf_idx];
+        const up_values = self.hybrid_csr_up_values[buf_idx];
+        const down_row_ptr = self.hybrid_csr_down_row_ptr[buf_idx];
+        const down_col_idx = self.hybrid_csr_down_col_idx[buf_idx];
+        const down_values = self.hybrid_csr_down_values[buf_idx];
+
+        // Pass 1: Gate + Up + SwiGLU with sparse corrections
+        {
+            const encoder = objc.commandBufferComputeEncoder(cmd_buf) orelse {
+                return error.MetalEncoderCreationFailed;
+            };
+            objc.encoderSetPipelineState(encoder, self.pipeline_expert_q2k_sparse);
+
+            // Base buffers
+            objc.encoderSetBuffer(encoder, input_buf, 0, 0);
+            objc.encoderSetBuffer(encoder, gate_q2k_buf, 0, 1);
+            objc.encoderSetBuffer(encoder, up_q2k_buf, 0, 2);
+            objc.encoderSetBuffer(encoder, down_q2k_buf, 0, 3); // Not used in pass 1
+            objc.encoderSetBuffer(encoder, self.buf_intermediate, 0, 4);
+            objc.encoderSetBuffer(encoder, self.buf_intermediate, 0, 5);
+            objc.encoderSetBuffer(encoder, self.buf_expert_output, 0, 6);
+
+            // Scalar parameters
+            const batch_size: u32 = 1;
+            const batch_offset: u32 = 0;
+            var batch_val = batch_size;
+            var n_embd_val = n_embd;
+            var n_ff_val = n_ff;
+            var offset_val = batch_offset;
+            objc.encoderSetBytes(encoder, @ptrCast(&batch_val), @sizeOf(u32), 7);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_embd_val), @sizeOf(u32), 8);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_ff_val), @sizeOf(u32), 9);
+            objc.encoderSetBytes(encoder, @ptrCast(&offset_val), @sizeOf(u32), 10);
+
+            // Token indices (nullptr for single token)
+            objc.encoderSetBuffer(encoder, null, 0, 11);
+
+            // Gate CSR outliers
+            if (gate_row_ptr) |buf| objc.encoderSetBuffer(encoder, buf, 0, 12);
+            if (gate_col_idx) |buf| objc.encoderSetBuffer(encoder, buf, 0, 13);
+            if (gate_values) |buf| objc.encoderSetBuffer(encoder, buf, 0, 14);
+
+            // Up CSR outliers
+            if (up_row_ptr) |buf| objc.encoderSetBuffer(encoder, buf, 0, 15);
+            if (up_col_idx) |buf| objc.encoderSetBuffer(encoder, buf, 0, 16);
+            if (up_values) |buf| objc.encoderSetBuffer(encoder, buf, 0, 17);
+
+            const threadgroups = objc.MTLSize{ .width = 1, .height = n_ff, .depth = 1 };
+            const threads_per_group = objc.MTLSize{ .width = 1, .height = 32, .depth = 1 };
+            objc.encoderDispatchThreadgroups(encoder, threadgroups, threads_per_group);
+            objc.encoderEndEncoding(encoder);
+        }
+
+        // Pass 2: Down projection with sparse corrections
+        {
+            const encoder = objc.commandBufferComputeEncoder(cmd_buf) orelse {
+                return error.MetalEncoderCreationFailed;
+            };
+            objc.encoderSetPipelineState(encoder, self.pipeline_down_proj_q2k_sparse);
+
+            objc.encoderSetBuffer(encoder, down_q2k_buf, 0, 0);
+            objc.encoderSetBuffer(encoder, self.buf_intermediate, 0, 1);
+            objc.encoderSetBuffer(encoder, self.buf_expert_output, 0, 2);
+
+            const batch_size: u32 = 1;
+            const batch_offset: u32 = 0;
+            var batch_val = batch_size;
+            var n_embd_val = n_embd;
+            var n_ff_val = n_ff;
+            var offset_val = batch_offset;
+            objc.encoderSetBytes(encoder, @ptrCast(&batch_val), @sizeOf(u32), 3);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_embd_val), @sizeOf(u32), 4);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_ff_val), @sizeOf(u32), 5);
+            objc.encoderSetBytes(encoder, @ptrCast(&offset_val), @sizeOf(u32), 6);
+
+            // Token indices (nullptr for single token)
+            objc.encoderSetBuffer(encoder, null, 0, 7);
+
+            // Down CSR outliers
+            if (down_row_ptr) |buf| objc.encoderSetBuffer(encoder, buf, 0, 8);
+            if (down_col_idx) |buf| objc.encoderSetBuffer(encoder, buf, 0, 9);
+            if (down_values) |buf| objc.encoderSetBuffer(encoder, buf, 0, 10);
+
+            const threadgroups = objc.MTLSize{ .width = 1, .height = n_embd, .depth = 1 };
+            const threads_per_group = objc.MTLSize{ .width = 1, .height = 32, .depth = 1 };
+            objc.encoderDispatchThreadgroups(encoder, threadgroups, threads_per_group);
+            objc.encoderEndEncoding(encoder);
+        }
+
+        // Pass 3: Weighted add to output accumulator (same as Q4 path)
+        {
+            const encoder = objc.commandBufferComputeEncoder(cmd_buf) orelse {
+                return error.MetalEncoderCreationFailed;
+            };
+            objc.encoderSetPipelineState(encoder, self.pipeline_moe_expert_weighted_add);
+            objc.encoderSetBuffer(encoder, self.buf_expert_output, 0, 0);
+            objc.encoderSetBuffer(encoder, output_buf, 0, 1);
+            var weight_val = weight;
+            var n_embd_val = n_embd;
+            objc.encoderSetBytes(encoder, @ptrCast(&weight_val), @sizeOf(f32), 2);
+            objc.encoderSetBytes(encoder, @ptrCast(&n_embd_val), @sizeOf(u32), 3);
+            const threads = objc.MTLSize{ .width = n_embd, .height = 1, .depth = 1 };
+            const threads_per_group = objc.MTLSize{ .width = 256, .height = 1, .depth = 1 };
+            objc.encoderDispatchThreads(encoder, threads, threads_per_group);
+            objc.encoderEndEncoding(encoder);
+        }
+    }
+
